2	  const result: [number, number][] = [];
3	  for (const [x, y] of cells) {
4	    let count = 0;
5	    for (const [nx, ny] of cells) {
6	      if (nx === x && ny === y) continue;
7	      if (Math.abs(nx - x) <= 1 && Math.abs(ny - y) <= 1) count++;
8	    }
9	    if (count === 2 || count === 3) result.push([x, y]);
